import{_ as t,c as a,o,a5 as r}from"./chunks/framework.CVIjMMbU.js";const p=JSON.parse('{"title":"How to Insert a Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"docs/howtos/how-to-input-matrices.md","filePath":"docs/howtos/how-to-input-matrices.md","lastUpdated":1773648703000}'),i={name:"docs/howtos/how-to-input-matrices.md"};function n(d,e,l,s,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="how-to-insert-a-matrix" tabindex="-1">How to Insert a Matrix <a class="header-anchor" href="#how-to-insert-a-matrix" aria-label="Permalink to “How to Insert a Matrix”">​</a></h1><h2 id="written-tutorial" tabindex="-1">Written Tutorial <a class="header-anchor" href="#written-tutorial" aria-label="Permalink to “Written Tutorial”">​</a></h2><h3 id="enter-math-mode" tabindex="-1">Enter Math Mode <a class="header-anchor" href="#enter-math-mode" aria-label="Permalink to “Enter Math Mode”">​</a></h3><ul><li>If you want to type a math formula, enter Math Mode first.</li><li>For inline math, type <code>$</code>.</li><li>For a display equation on its own line, use <code>Alt/Option</code> + <code>$</code>.</li></ul><h3 id="insert-a-matrix" tabindex="-1">Insert a Matrix <a class="header-anchor" href="#insert-a-matrix" aria-label="Permalink to “Insert a Matrix”">​</a></h3><ul><li>In Math Mode, press <code>Alt/Option</code> + <code>t</code>, then press <code>Tab</code> once to insert a matrix.</li><li>You can also press <code>\\</code> to enter command mode, type <code>matrix</code>, and press <code>Enter</code>.</li><li>A newly inserted matrix starts as <code>1 x 1</code>.</li></ul><h3 id="change-the-number-of-rows-and-columns" tabindex="-1">Change the Number of Rows and Columns <a class="header-anchor" href="#change-the-number-of-rows-and-columns" aria-label="Permalink to “Change the Number of Rows and Columns”">​</a></h3><ul><li>After inserting the matrix, use <code>Alt/Option</code> + the arrow keys to expand it.</li><li>Left and right add columns.</li><li>Up and down add rows.</li><li>For example, you can insert a matrix first and then expand it into a <code>3 x 3</code> matrix with <code>Alt/Option</code> + the arrow keys.</li></ul><h3 id="enter-values-in-the-matrix" tabindex="-1">Enter Values in the Matrix <a class="header-anchor" href="#enter-values-in-the-matrix" aria-label="Permalink to “Enter Values in the Matrix”">​</a></h3><ul><li>Type numbers, letters, or symbols directly into each cell.</li><li>To enter Greek letters, type the matching Latin letter first, then press <code>Tab</code> to cycle.</li></ul><p>Examples:</p><p><code>a</code> + <code>Tab</code> -&gt; <code>\\alpha</code></p><p><code>b</code> + <code>Tab</code> -&gt; <code>\\beta</code></p><p><code>g</code> + <code>Tab</code> -&gt; <code>\\gamma</code></p>',14)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
